To achieve one index cache per index file, you can modify your code to store the cache in the same directory as the index file. Here's an example of how you can implement this:

**Index Cache Manager**
```python
import os
import pickle

class IndexCacheManager:
    def __init__(self, index_file_path):
        self.index_file_path = index_file_path
        self.cache_file_path = os.path.join(os.path.dirname(index_file_path), '.index_cache')

    def load_cache(self):
        try:
            with open(self.cache_file_path, 'rb') as f:
                return pickle.load(f)
        except FileNotFoundError:
            return {}

    def save_cache(self, cache):
        with open(self.cache_file_path, 'wb') as f:
            pickle.dump(cache, f)

    def get_cache(self):
        return self.load_cache()

    def set_cache(self, cache):
        self.save_cache(cache)
